#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""화자 성별(근사) 부여 — 각 대사 줄에 gender: 남/여/미상. role_hint 자동 매핑 + BL/GL 예외.
남주(ML)→남, 여주(FL)→여, 조연(SUP)→미상(단 BL/GL은 예외), 나레이션→'', 미상(UNK)→미상.
텍스트 기반 근사(오디오 성별 판별 아님). 멱등."""
import json, os
BASE=os.path.dirname(os.path.abspath(__file__)); DB=os.path.join(BASE,"reference_db.json")

GENDER={"ML":"남","FL":"여","SUP":"미상","NAR":"","UNK":"미상"}
BL_MALE={"7544952986594741559","7644648326046043406"}   # 두 주연 남 → 조연도 남
GL_FEMALE={"7644620832018418960"}                        # 두 주연 여 → 조연도 여

# 0701 시드 38편: 예전 처리 버그로 role_hint가 화자N으로 덮여 복구 불가 → 편별 화자→성별 수작업 맵.
# (대본·context 기반 근사. 명시 안 된 화자는 미상)
SPK_0701={
"7656529518080986401":{"화자1":"남","화자2":"남"},
"7653462431334731028":{"화자1":"여","화자2":"남"},
"7610437534421667093":{"화자1":"남","화자2":"남"},
"7544952986594741559":{"화자1":"남","화자3":"남"},
"7657208716890230037":{"화자1":"여","화자2":"남"},
"7616529235447991566":{"화자1":"여","화자2":"여","화자3":"남"},
"7657213982906158357":{"화자3":"남"},
"7650648291595635981":{"화자1":"남","화자2":"여"},
"7610199274336423188":{"화자1":"여","화자2":"남"},
"7655032823597796622":{"화자1":"남","화자2":"여"},
"7616715247692369165":{"화자1":"여","화자2":"남"},
"7615912643504672021":{"화자1":"남"},
"7656801271600516365":{"화자1":"여","화자2":"남"},
"7635432540983102734":{"화자1":"여","화자2":"여","화자3":"남"},
"7656762507452894486":{"화자1":"여","화자4":"남"},
"7652410132625640718":{"화자2":"여"},
"7653244565159218452":{"화자1":"남","화자2":"여"},
"7565394066645454102":{"화자1":"여","화자2":"남"},
"7612034128392834324":{"화자1":"여","화자2":"남"},
"7623913145849122069":{"화자2":"남"},
"7643871694003686670":{"화자1":"여","화자2":"남"},
"7616121894068063508":{"화자1":"남","화자2":"여"},
"7579541494562917646":{"화자1":"남","화자3":"여"},
"7651919847521013012":{"화자2":"여","화자3":"남"},
"7657195947071474964":{"화자1":"여","화자2":"남"},
"7405538662022155537":{"화자1":"남","화자2":"여"},
"7548287851012623630":{"화자1":"남","화자2":"여"},
"7617971730228858132":{"화자1":"여","화자2":"남"},
"7644033381134634247":{"화자2":"여"},
"7625768871911279904":{"화자1":"여","화자2":"남"},
"7614643691378035988":{"화자1":"여","화자2":"남"},
"7652966782126263566":{"화자1":"여","화자2":"남"},
"7577762821618797855":{"화자1":"여","화자3":"남"},
"7649781763383758093":{"화자1":"여"},
"7654357061702077710":{"화자1":"여"},
}

def main():
    db=json.load(open(DB,encoding="utf-8"))
    n=0
    for r in db:
        bl=(r["id"] in BL_MALE) or (r.get("genre")=="bl"); gl=r["id"] in GL_FEMALE
        spkmap=SPK_0701.get(r["id"])
        for l in (r.get("script") or []):
            rh=l.get("role_hint","UNK")
            if rh in GENDER:  # role_hint 정상(0706/0707)
                g=GENDER[rh]
                if rh=="SUP" and bl: g="남"
                if rh=="SUP" and gl: g="여"
            else:  # role_hint 손상(0701) → 화자별 수작업 맵, 나레이션은 성별 없음
                sp=l.get("speaker","")
                g="" if sp=="나레이션" else (spkmap.get(sp,"미상") if spkmap else "미상")
            l["gender"]=g
        if r.get("script"): n+=1
    json.dump(db,open(DB,"w",encoding="utf-8"),ensure_ascii=False,indent=1)
    from collections import Counter
    c=Counter(l["gender"] for r in db for l in (r.get("script") or []))
    print(f"성별 부여: {n}편 | 줄 성별 분포 {dict(c)}")

if __name__=="__main__": main()
